example.code:
// Include directly in design.md
interface CreateUserRequest {
  email: string;      // RFC 5322 format
  password: string;   // Min 8 chars, 1 uppercase, 1 number
}

interface CreateUserResponse {
  user: {
    id: string;       // UUID v4
    email: string;
    createdAt: Date;
  };
}

### POST /api/users

**Request:**
{"email": "user@example.com", "password": "SecurePass1"}

**Response (201):**
{"user": {"id": "uuid-v4", "email": "user@example.com", "createdAt": "ISO8601"}}

**Errors:**
- 400: validation failure {"error": {"code": "VALIDATION_ERROR", "details": [...]}}
- 409: email exists {"error": {"code": "DUPLICATE_EMAIL"}}
- 500: server error {"error": {"code": "INTERNAL_ERROR", "request_id": "..."}}
